#!/usr/bin/env python
"""Patch the installed Inspect Anthropic provider to report *billed* thinking.

Inspect's Anthropic provider derives ``ModelUsage.reasoning_tokens`` by
re-tokenizing the returned ``ThinkingBlock`` text. For Claude 4.x that text is a
*summary* generated by a separate model: it is not the billed thinking, is often
longer than the real reasoning (it can exceed ``output_tokens``), and is empty
entirely under ``thinking.display="omitted"`` (the Opus 4.7/4.8 default). The
authoritative, billing-inclusive count is
``usage.output_tokens_details.thinking_tokens``
(https://platform.claude.com/docs/en/build-with-claude/adaptive-thinking).

Two edits are required, because Inspect always *streams* for thinking models and
the Anthropic SDK's streaming accumulator drops ``usage.output_tokens_details``
(sets it to ``None``) even though every ``message_delta`` event carries it:

1. ``_capture_compaction_from_stream`` — capture ``output_tokens_details`` from
   the streamed ``message_delta`` events and restore it onto the final snapshot.
2. ``model_output_from_message`` — prefer
   ``usage.output_tokens_details.thinking_tokens`` over re-tokenizing the summary,
   falling back to the summary count only when the field is absent.

Inspect is launched as a subprocess (``.venv/bin/inspect eval``), so an in-process
monkeypatch from ObviousBench would not reach it. This script edits the installed
package file directly. Each edit is independently idempotent (guarded by a
sentinel), so the script can be re-run after any ``pip install`` / env rebuild. It
fails loudly if an upstream anchor no longer matches, so drift is noticed.

Usage:
    .venv/bin/python scripts/patch_inspect_anthropic_thinking_tokens.py [--check]
"""

from __future__ import annotations

import argparse
import sys
from pathlib import Path

# (sentinel, anchor_to_replace, replacement) tuples. An edit is skipped when its
# sentinel is already present.
EDITS: list[tuple[str, str, str]] = [
    (
        "_ob_output_tokens_details",
        """\
    compaction_content: str | None = None

    # Iterate through all streaming events to capture compaction_delta content
    async for event in stream:
        if (
            hasattr(event, "delta")
            and getattr(event.delta, "type", None) == "compaction_delta"
        ):
            compaction_content = getattr(event.delta, "content", None)

    # Get the final message snapshot
    message = stream.current_message_snapshot
""",
        """\
    compaction_content: str | None = None
    _ob_output_tokens_details = None  # [ObviousBench patch: billed thinking]

    # Iterate through all streaming events to capture compaction_delta content
    async for event in stream:
        if (
            hasattr(event, "delta")
            and getattr(event.delta, "type", None) == "compaction_delta"
        ):
            compaction_content = getattr(event.delta, "content", None)
        # [ObviousBench patch] capture billed thinking from message_delta usage;
        # the SDK's final snapshot drops usage.output_tokens_details (-> None).
        _ob_ev_usage = getattr(event, "usage", None)
        if _ob_ev_usage is not None:
            _ob_otd = getattr(_ob_ev_usage, "output_tokens_details", None)
            if _ob_otd is not None and getattr(_ob_otd, "thinking_tokens", None) is not None:
                _ob_output_tokens_details = _ob_otd

    # Get the final message snapshot
    message = stream.current_message_snapshot

    # [ObviousBench patch] restore billed thinking onto the snapshot usage
    if (
        _ob_output_tokens_details is not None
        and getattr(message, "usage", None) is not None
        and getattr(message.usage, "output_tokens_details", None) is None
    ):
        try:
            message.usage.output_tokens_details = _ob_output_tokens_details
        except Exception:
            pass
""",
    ),
    (
        "_ob_thinking",
        """\
    # count reasoning tokens
    reasoning_tokens = 0
    if client and model:
        for content_block in message.content:
            if isinstance(content_block, ThinkingBlock):
                reasoning_tokens += await count_tokens(
                    client, model, content_block.thinking
                )
""",
        """\
    # count reasoning tokens [ObviousBench patch: prefer billed thinking]
    # Prefer the provider's authoritative billed count
    # (usage.output_tokens_details.thinking_tokens, the raw reasoning the model
    # generated) over re-tokenizing the returned ThinkingBlock text, which for
    # Claude 4.x is a separate summary -- often longer than the billed thinking,
    # and empty entirely under display="omitted". Fall back to the summary count
    # for usage objects that do not report thinking_tokens (e.g. Sonnet 3.7).
    reasoning_tokens = 0
    _ob_usage_dump = message.usage.model_dump()
    _ob_otd = _ob_usage_dump.get("output_tokens_details") or {}
    _ob_thinking = _ob_otd.get("thinking_tokens")
    if _ob_thinking is not None:
        reasoning_tokens = int(_ob_thinking)
    elif client and model:
        for content_block in message.content:
            if isinstance(content_block, ThinkingBlock):
                reasoning_tokens += await count_tokens(
                    client, model, content_block.thinking
                )
""",
    ),
]


def provider_path() -> Path:
    try:
        from inspect_ai.model._providers import anthropic as _anthropic
    except Exception as exc:  # noqa: BLE001
        raise SystemExit(f"could not import Inspect Anthropic provider: {exc}") from exc
    return Path(_anthropic.__file__)


def main(argv: list[str] | None = None) -> int:
    parser = argparse.ArgumentParser(prog="patch_inspect_anthropic_thinking_tokens.py")
    parser.add_argument(
        "--check",
        action="store_true",
        help="Exit 0 if all edits already applied, 1 otherwise; make no changes.",
    )
    args = parser.parse_args(argv)

    path = provider_path()
    source = path.read_text(encoding="utf-8")

    pending = [(s, a, r) for (s, a, r) in EDITS if s not in source]
    if not pending:
        print(f"already patched (all edits present): {path}")
        return 0
    if args.check:
        missing = ", ".join(s for s, _, _ in pending)
        print(f"NOT fully patched: {path} (missing: {missing})")
        return 1

    for sentinel, anchor, replacement in pending:
        if anchor not in source:
            raise SystemExit(
                f"upstream anchor for '{sentinel}' not found -- Inspect provider "
                f"has drifted; re-derive the patch against {path}"
            )
        source = source.replace(anchor, replacement, 1)
    path.write_text(source, encoding="utf-8")
    print(f"patched ({len(pending)} edit(s)): {path}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main(sys.argv[1:]))
